import type { Request, Response } from "express";
import { randomUUID } from "node:crypto";
import { AppError } from "../../utils/appError.js";
import type { TestResource } from "../../types/api.js";

const testStore = new Map<string, TestResource>();

export const listTestsController = (_req: Request, res: Response) => {
  res.status(200).json({
    data: Array.from(testStore.values())
  });
};

export const getTestController = (req: Request, res: Response) => {
  const resource = testStore.get(req.params.id);

  if (!resource) {
    throw new AppError(404, "Test resource not found");
  }

  res.status(200).json({ data: resource });
};

export const createTestController = (req: Request, res: Response) => {
  const now = new Date().toISOString();
  const id = randomUUID();

  const resource: TestResource = {
    id,
    name: req.body.name,
    active: req.body.active ?? true,
    createdAt: now,
    updatedAt: now
  };

  testStore.set(id, resource);

  res.status(201).json({ data: resource });
};

export const updateTestController = (req: Request, res: Response) => {
  const existingResource = testStore.get(req.params.id);

  if (!existingResource) {
    throw new AppError(404, "Test resource not found");
  }

  const updatedResource: TestResource = {
    ...existingResource,
    ...req.body,
    updatedAt: new Date().toISOString()
  };

  testStore.set(existingResource.id, updatedResource);

  res.status(200).json({ data: updatedResource });
};

export const deleteTestController = (req: Request, res: Response) => {
  const exists = testStore.has(req.params.id);

  if (!exists) {
    throw new AppError(404, "Test resource not found");
  }

  testStore.delete(req.params.id);

  res.status(204).send();
};

import { Router } from "express";
import {
  createTestController,
  deleteTestController,
  getTestController,
  listTestsController,
  updateTestController
} from "../../controllers/test/test.controller.js";
import { validate } from "../../middleware/validate.js";
import {
  createTestSchema,
  testParamsSchema,
  updateTestSchema
} from "../../schemas/test/test.schema.js";

export const testRouter = Router();

testRouter.get("/", listTestsController);
testRouter.get("/:id", validate({ params: testParamsSchema }), getTestController);
testRouter.post("/", validate({ body: createTestSchema }), createTestController);
testRouter.put(
  "/:id",
  validate({ params: testParamsSchema, body: updateTestSchema }),
  updateTestController
);
testRouter.delete("/:id", validate({ params: testParamsSchema }), deleteTestController);

import { z } from "zod";

export const testParamsSchema = z.object({
  id: z.string().min(1)
});

export const createTestSchema = z.object({
  name: z.string().trim().min(1).max(100),
  active: z.boolean().default(true)
});

export const updateTestSchema = createTestSchema.partial().refine(
  (value) => Object.keys(value).length > 0,
  "At least one field must be provided"
);
